css:
.loader {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
  width: 120px;
  height: 20px;
  background: linear-gradient(var(--loader-color, #0284c7) 0 0) left -40px top 0/40px 100% no-repeat var(--loader-secondary-color, #7dd3fc);
  -webkit-mask:conic-gradient(from 90deg at 5px 5px,#0000 25%,currentColor 0)0 0/calc((100% - 5px)/5) calc(100% - 5px);
  animation: l10 1s infinite linear;
}@keyframes l10 {100% {background-position: right -40px top 0}}
